static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;
    const gert::Shape &xShape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t batchSize = static_cast<uint32_t>(xShape.GetDim(0));
    const uint32_t outFeatures = static_cast<uint32_t>(xShape.GetDim(1));
    const uint32_t totalLength = batchSize * outFeatures;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *numGroupsPtr = attrs->GetAttrPointer<int64_t>(0);
    const float *epsilonPtr = attrs->GetAttrPointer<float>(1);
    const uint32_t numGroups = static_cast<uint32_t>(*numGroupsPtr);
    const float epsilon = *epsilonPtr;
    const uint32_t groupSize = outFeatures / numGroups;

    uint32_t maxTile = UB_BUDGET_BYTES / (6 * sizeof(float)); // x, bias, gamma, beta, y + temporaries
